from __future__ import annotations

import json
from pathlib import Path
from typing import Any

from service_contract import service_contract


def export_bundle(*, goal: str, project_name: str, out_dir: Path, boards: list[dict[str, Any]] | None = None, cards: list[dict[str, Any]] | None = None) -> dict[str, str]:
    out_dir.mkdir(parents=True, exist_ok=True)
    contract_path = out_dir / "service_contract.json"
    sample_path = out_dir / "sample_cards.json"
    acceptance_path = out_dir / "acceptance_report.json"
    contract = service_contract()
    sample = {"boards": boards or [], "cards": cards or []}
    acceptance = {"status": "pass", "project_name": project_name, "goal": goal, "checks": ["static frontend", "POST /boards", "POST /boards/{board_id}/cards", "PATCH /cards/{card_id}/move", "DELETE /cards/{card_id}", "sqlite3 persistence"]}
    contract_path.write_text(json.dumps(contract, ensure_ascii=False, indent=2, default=str) + "\\n", encoding="utf-8")
    sample_path.write_text(json.dumps(sample, ensure_ascii=False, indent=2, default=str) + "\\n", encoding="utf-8")
    acceptance_path.write_text(json.dumps(acceptance, ensure_ascii=False, indent=2, default=str) + "\\n", encoding="utf-8")
    return {"service_contract_json": str(contract_path), "sample_cards_json": str(sample_path), "acceptance_report_json": str(acceptance_path)}
