KANBAN_STORE = textwrap.dedent("""
from __future__ import annotations

import sqlite3
from contextlib import contextmanager
from datetime import datetime, timezone
from pathlib import Path
from typing import Iterator


ALLOWED_COLUMNS = {"todo", "doing", "done"}


class KanbanStore:
    def __init__(self, db_path: Path) -> None:
        self.db_path = Path(db_path)
        self.db_path.parent.mkdir(parents=True, exist_ok=True)
        self._init_db()

    @contextmanager
    def _connect(self) -> Iterator[sqlite3.Connection]:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        try:
            yield conn
        finally:
            conn.close()

    def _init_db(self) -> None:
        with self._connect() as conn:
            conn.execute("CREATE TABLE IF NOT EXISTS boards (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL)")
            conn.execute("CREATE TABLE IF NOT EXISTS cards (id INTEGER PRIMARY KEY AUTOINCREMENT, board_id INTEGER NOT NULL, title TEXT NOT NULL, description TEXT NOT NULL, column_name TEXT NOT NULL, position INTEGER NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY(board_id) REFERENCES boards(id))")
            conn.commit()

    def _board(self, row: sqlite3.Row | None) -> dict[str, object] | None:
        return None if row is None else {"id": int(row["id"]), "name": row["name"]}

    def _card(self, row: sqlite3.Row | None) -> dict[str, object] | None:
        if row is None:
            return None
        return {"id": int(row["id"]), "board_id": int(row["board_id"]), "title": row["title"], "description": row["description"], "column": row["column_name"], "position": int(row["position"]), "created_at": row["created_at"], "updated_at": row["updated_at"]}

    def create_board(self, name: str) -> dict[str, object]:
        name = str(name or "").strip() or "Kanban Board"
        with self._connect() as conn:
            cur = conn.execute("INSERT INTO boards (name) VALUES (?)", (name,))
            board_id = int(cur.lastrowid)
            conn.commit()
        return self.get_board(board_id) or {}

    def list_boards(self) -> list[dict[str, object]]:
        with self._connect() as conn:
            return [self._board(row) or {} for row in conn.execute("SELECT * FROM boards ORDER BY id")]

    def get_board(self, board_id: int) -> dict[str, object] | None:
        with self._connect() as conn:
            return self._board(conn.execute("SELECT * FROM boards WHERE id=?", (board_id,)).fetchone())

    def create_card(self, board_id: int, title: str, description: str = "", column: str = "todo") -> dict[str, object] | None:
        if self.get_board(board_id) is None:
            return None
        title = str(title or "").strip()
        if not title:
            raise ValueError("title_required")
        column = column if column in ALLOWED_COLUMNS else "todo"
        now = datetime.now(timezone.utc).isoformat()
        with self._connect() as conn:
            row = conn.execute("SELECT COALESCE(MAX(position), 0) + 1 FROM cards WHERE board_id=? AND column_name=?", (board_id, column)).fetchone()
            position = int(row[0] if row else 1)
            cur = conn.execute("INSERT INTO cards (board_id, title, description, column_name, position, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)", (board_id, title, str(description or ""), column, position, now, now))
            card_id = int(cur.lastrowid)
            conn.commit()
        return self.get_card(card_id)

    def list_cards(self, board_id: int) -> list[dict[str, object]]:
        with self._connect() as conn:
            return [self._card(row) or {} for row in conn.execute("SELECT * FROM cards WHERE board_id=? ORDER BY column_name, position, id", (board_id,))]

    def get_card(self, card_id: int) -> dict[str, object] | None:
        with self._connect() as conn:
            return self._card(conn.execute("SELECT * FROM cards WHERE id=?", (card_id,)).fetchone())

    def update_card(self, card_id: int, fields: dict[str, object]) -> dict[str, object] | None:
        current = self.get_card(card_id)
        if current is None:
            return None
        title = str(fields.get("title", current["title"])).strip() or str(current["title"])
        description = str(fields.get("description", current["description"]))
        now = datetime.now(timezone.utc).isoformat()
        with self._connect() as conn:
            conn.execute("UPDATE cards SET title=?, description=?, updated_at=? WHERE id=?", (title, description, now, card_id))
            conn.commit()
        return self.get_card(card_id)

    def move_card(self, card_id: int, column: str, position: int | None = None) -> dict[str, object] | None:
        if column not in ALLOWED_COLUMNS or self.get_card(card_id) is None:
            return None
        if position is None or position < 1:
            position = 1
        now = datetime.now(timezone.utc).isoformat()
        with self._connect() as conn:
            conn.execute("UPDATE cards SET column_name=?, position=?, updated_at=? WHERE id=?", (column, int(position), now, card_id))
            conn.commit()
        return self.get_card(card_id)

    def delete_card(self, card_id: int) -> bool:
        with self._connect() as conn:
            cur = conn.execute("DELETE FROM cards WHERE id=?", (card_id,))
            conn.commit()
            return cur.rowcount > 0

    def close(self) -> None:
        return None
""").lstrip()


KANBAN_APP = textwrap.dedent("""
from __future__ import annotations

import argparse
import json
import mimetypes
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from pathlib import Path
from urllib.parse import urlparse

from kanban_store import KanbanStore


def json_response(handler: BaseHTTPRequestHandler, status: int, payload: dict[str, object]) -> None:
    raw = json.dumps(payload, ensure_ascii=False, default=str).encode("utf-8")
    handler.send_response(status)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(raw)))
    handler.end_headers()
    handler.wfile.write(raw)


def read_json(handler: BaseHTTPRequestHandler) -> dict[str, object]:
    size = int(handler.headers.get("Content-Length", "0") or 0)
    if size <= 0:
        return {}
    try:
        value = json.loads(handler.rfile.read(size).decode("utf-8", errors="replace"))
    except json.JSONDecodeError:
        return {}
    return value if isinstance(value, dict) else {}


def split_path(path: str) -> list[str]:
    return [part for part in urlparse(path).path.strip("/").split("/") if part]


class KanbanHandler(BaseHTTPRequestHandler):
    store: KanbanStore
    static_dir: Path

    def log_message(self, format: str, *args: object) -> None:
        return

    def _send_file(self, path: Path) -> None:
        if not path.exists() or not path.is_file():
            json_response(self, 404, {"error": "not_found"})
            return
        raw = path.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", mimetypes.guess_type(str(path))[0] or "application/octet-stream")
        self.send_header("Content-Length", str(len(raw)))
        self.end_headers()
        self.wfile.write(raw)

    def do_GET(self) -> None:
        parts = split_path(self.path)
        if parts == []:
            self._send_file(self.static_dir / "index.html")
        elif parts == ["status"]:
            json_response(self, 200, {"status": "ok", "service": "local_kanban_board_app"})
        elif parts == ["boards"]:
            json_response(self, 200, {"boards": self.store.list_boards()})
        elif len(parts) == 3 and parts[0] == "boards" and parts[1].isdigit() and parts[2] == "cards":
            json_response(self, 200, {"cards": self.store.list_cards(int(parts[1]))})
        elif len(parts) == 2 and parts[0] == "static":
            self._send_file(self.static_dir / parts[1])
        else:
            json_response(self, 404, {"error": "not_found"})

    def do_POST(self) -> None:
        parts = split_path(self.path)
        payload = read_json(self)
        if parts == ["boards"]:
            board = self.store.create_board(str(payload.get("name", "")))
            json_response(self, 201, {"board": board, "id": board["id"]})
        elif len(parts) == 3 and parts[0] == "boards" and parts[1].isdigit() and parts[2] == "cards":
            try:
                card = self.store.create_card(int(parts[1]), str(payload.get("title", "")), str(payload.get("description", "")), str(payload.get("column", "todo")))
            except ValueError:
                json_response(self, 400, {"error": "title_required"})
                return
            json_response(self, 201 if card else 404, {"card": card, "id": card["id"]} if card else {"error": "board_not_found"})
        else:
            json_response(self, 404, {"error": "not_found"})

    def do_PATCH(self) -> None:
        parts = split_path(self.path)
        payload = read_json(self)
        if len(parts) == 3 and parts[0] == "cards" and parts[1].isdigit() and parts[2] == "move":
            card = self.store.move_card(int(parts[1]), str(payload.get("column", "")), int(payload.get("position", 1) or 1))
            json_response(self, 200 if card else 404, {"card": card} if card else {"error": "not_found"})
        elif len(parts) == 2 and parts[0] == "cards" and parts[1].isdigit():
            card = self.store.update_card(int(parts[1]), payload)
            json_response(self, 200 if card else 404, {"card": card} if card else {"error": "not_found"})
        else:
            json_response(self, 404, {"error": "not_found"})

    def do_DELETE(self) -> None:
        parts = split_path(self.path)
        if len(parts) == 2 and parts[0] == "cards" and parts[1].isdigit():
            deleted = self.store.delete_card(int(parts[1]))
            json_response(self, 200 if deleted else 404, {"deleted": deleted} if deleted else {"error": "not_found"})
        else:
            json_response(self, 404, {"error": "not_found"})


def create_server(host: str, port: int, db_path: Path, static_dir: Path | None = None) -> ThreadingHTTPServer:
    KanbanHandler.store = KanbanStore(db_path)
    KanbanHandler.static_dir = Path(static_dir) if static_dir else Path(__file__).resolve().parent / "static"
    return ThreadingHTTPServer((host, port), KanbanHandler)


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="127.0.0.1")
    parser.add_argument("--port", type=int, default=8000)
    parser.add_argument("--db", default="kanban_board.db")
    parser.add_argument("--goal", default="")
    parser.add_argument("--project-name", default="local_kanban_board_app")
    parser.add_argument("--out", default="")
    args = parser.parse_args()
    if args.out:
        import json
        from service import generate_project

        result = generate_project(goal=args.goal or "smoke export", project_name=args.project_name, out_dir=Path(args.out))
        print(json.dumps(result, ensure_ascii=False, indent=2, default=str))
        return 0
    server = create_server(args.host, args.port, Path(args.db))
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        server.server_close()
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
""").lstrip()


