KANBAN_APP_JS = textwrap.dedent("""
let activeBoardId = null;
const columns = {
  todo: document.querySelector("#column-todo"),
  doing: document.querySelector("#column-doing"),
  done: document.querySelector("#column-done"),
};

async function api(path, options = {}) {
  const response = await fetch(path, {
    headers: {"Content-Type": "application/json", "Accept": "application/json"},
    ...options,
  });
  return response.json();
}

async function ensureBoard() {
  const payload = await api("/boards");
  if (payload.boards.length > 0) {
    activeBoardId = payload.boards[0].id;
    document.querySelector("#board-title").textContent = payload.boards[0].name;
    return;
  }
  const created = await api("/boards", {method: "POST", body: JSON.stringify({name: "Local Kanban Board"})});
  activeBoardId = created.id;
  document.querySelector("#board-title").textContent = created.board.name;
}

function cardNode(card) {
  const item = document.createElement("li");
  item.className = "card";
  item.dataset.cardId = card.id;
  item.innerHTML = `<strong>${card.title}</strong><p>${card.description || ""}</p><div class="actions">
    <button data-move="todo">Todo</button>
    <button data-move="doing">Doing</button>
    <button data-move="done">Done</button>
    <button data-delete="true">Delete</button>
  </div>`;
  item.querySelectorAll("button[data-move]").forEach((button) => {
    button.addEventListener("click", async () => {
      await moveCard(card.id, button.dataset.move);
    });
  });
  item.querySelector("button[data-delete]").addEventListener("click", async () => {
    await api(`/cards/${card.id}`, {method: "DELETE"});
    await loadCards();
  });
  return item;
}

async function moveCard(cardId, column) {
  await api(`/cards/${cardId}/move`, {method: "PATCH", body: JSON.stringify({column, position: 1})});
  await loadCards();
}

async function loadCards() {
  Object.values(columns).forEach((column) => column.replaceChildren());
  const payload = await api(`/boards/${activeBoardId}/cards`);
  for (const card of payload.cards) {
    (columns[card.column] || columns.todo).appendChild(cardNode(card));
  }
}

document.querySelector("#card-form").addEventListener("submit", async (event) => {
  event.preventDefault();
  const title = document.querySelector("#card-title");
  const description = document.querySelector("#card-description");
  await api(`/boards/${activeBoardId}/cards`, {method: "POST", body: JSON.stringify({title: title.value, description: description.value, column: "todo"})});
  title.value = "";
  description.value = "";
  await loadCards();
});

ensureBoard().then(loadCards);
""").lstrip()


