def kanban_project_files(*, goal_text: str, project_id: str, project_root: str, workflow_doc_rel: str, provenance: dict[str, object]) -> dict[str, str]:
    files = {
        "README.md": _kanban_readme(goal_text),
        "app.py": KANBAN_APP,
        "kanban_store.py": KANBAN_STORE,
        "models.py": KANBAN_MODELS,
        "service_contract.py": _kanban_contract(project_id),
        "service.py": KANBAN_SERVICE,
        "exporter.py": KANBAN_EXPORTER,
        "tests/test_kanban_service.py": KANBAN_TESTS,
        "tests/__init__.py": "# generated test package\n",
        **static_asset_files(index_html=KANBAN_INDEX_HTML, app_js=KANBAN_APP_JS, styles_css=KANBAN_STYLES),
        **standard_support_files(
            project_id=project_id,
            workflow_doc_rel=workflow_doc_rel,
            provenance=provenance,
            core_notes="# Core Runtime Notes\n\n- project_id: local_kanban_board_app\n- frontend: static_html_css_js\n- storage: sqlite3\n- ordinary_mainline: new-run/status/advance/source_generation\n",
            workflow_notes="# Kanban Full Stack Workflow\n\n- Serve static frontend.\n- Expose JSON board/card API.\n- Persist boards and cards in SQLite.\n- Validate frontend, API, card movement, and persistence.\n",
        ),
    }
    return prefixed_files(project_root, files)
